#include <stdio.h>
#include <string.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char s[100005]; scanf("%s", s);
        int cnt[26] = {0};
        int l = 0, best = 0;
        for(int r = 0; r < N; ++r){
            int idx = s[r] - 'a';
            cnt[idx]++;
            while(cnt[idx] > idx+1){
                int leftIdx = s[l] - 'a';
                cnt[leftIdx]--;
                l++;
            }
            int len = r - l + 1;
            if(len > best) best = len;
        }
        printf("%d\n", best);
    }
    return 0;
}

