#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N; string s; cin>>s;
        int cnt[26] = {};
        int l=0, best=0;
        for(int r=0;r<N;++r){
            int idx=s[r]-'a';
            ++cnt[idx];
            while(cnt[idx] > idx+1){
                int leftIdx=s[l]-'a';
                --cnt[leftIdx];
                ++l;
            }
            best=max(best, r-l+1);
        }
        cout<<best<<"\n";
    }
    return 0;
}

