    while (cnt[cIdx] > cIdx + 1) {
      const leftIdx = s.charCodeAt(l) - 97;
      cnt[leftIdx]--;
      l++;
    }
    const len = r - l + 1;
    if (len > best) best = len;
  }
  outputs.push(String(best));
